sysauto_script.script:
var gr = new GlideRecord('x_1956461_vendor_0_vendor_table');

// Only active records with expiry date
gr.addActiveQuery();
gr.addQuery('state', 'active');
gr.addNotNullQuery('expiry_date');

gr.query();

while (gr.next()) {

    var today = new GlideDateTime();
    var expiry = new GlideDateTime(gr.getValue('expiry_date'));

    // Difference in milliseconds
    var diff = expiry.getNumericValue() - today.getNumericValue();

    // Convert milliseconds to days
    var daysRemaining = Math.floor(diff / (1000 * 60 * 60 * 24));

    gs.info(`email event triggred--------${daysRemaining}`);

    // Send reminders
    if (daysRemaining < 0) {

        gr.state = 'expired';
        gr.active = false;

        gr.update();

        gs.eventQueue(
            'x_1956461_vendor_0.vendorExpiryReminder',
            gr,
            'today',
            gr.getValue('contact_email')
        );
    } else if (daysRemaining == 90 || daysRemaining == 60 || daysRemaining == 45 || daysRemaining == 29 || daysRemaining == 14 || daysRemaining == 7) {

        gs.info('email event triggred', gr);
        gs.eventQueue(
            'x_1956461_vendor_0.vendorExpiryReminder',
            gr,
            daysRemaining,
            gr.getValue('contact_email')
        );
    }

}
